import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-29f7914e.js";const p={},e=t(`<h2 id="_1-스코프란" tabindex="-1"><a class="header-anchor" href="#_1-스코프란" aria-hidden="true">#</a> 1. 스코프란?</h2><p>스코프(유효범위)는 자바스크립트를 포함한 모든 프로그래밍 언어의 기본적이며 중요한 개념이다.<br> 스코프는 변수 그리고 함수와 깊은 관련이 있다.<br> 함수의 매개변수는 함수 몸체 내부에서만 참조할 수 있고 몸체 외부에서는 참조할 수 없다고 했다.<br> 이것은 매개변수를 참조할 수 있는 유효범위, 즉 매개변수의 스코프가 함수 몸체 내부로 한정되기 때문이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">add</span><span class="token punctuation">(</span><span class="token parameter">x<span class="token punctuation">,</span> y</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">,</span> y<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> x <span class="token operator">+</span> y<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">add</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 매개변수는 함수 몸체 내부에서만 참조할 수 있다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">,</span> y<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>변수는 코드의 가장 바깥 영역뿐 아니라 코드 블록이나 함수 몸체 내에서도 선언할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> var1 <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> var2 <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">var</span> var3 <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> var4 <span class="token operator">=</span> <span class="token number">4</span><span class="token punctuation">;</span>

  <span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">var</span> var5 <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>var1<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>var2<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 2</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>var3<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 3</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>var4<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>var5<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>모든 식별자(변수 이름, 함수 이름, 클래스 이름 등)은 자신이 선언된 위치에 의해 다른 코드가 식별자 자신을 참조할 수 있는<br> 유효범위가 결정된다.</p><p>스코프는 식별자가 유효한 범위를 말한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token string">&quot;global&quot;</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token string">&quot;local&quot;</span><span class="token punctuation">;</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ①</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ②</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>코드의 가장 바깥 영역과 foo 함수 내부에 같은 이름을 갖는 x 변수를 선언했고 ①과 ②에서 x 변수를 참조한다.<br> 이때 자바스크립트 엔진은 이름이 같은 두 개의 변수 중 어떤 변수를 참조해야 할 것인지를 결정해야 한다.</p><p>이를 <strong>식별자 결정</strong>이라 한다.</p><div class="hint-container info"><p class="hint-container-title">코드의 문맥과 환경</p><p><strong>코드가 어디서 실행되며 주변에 어떤 코드가 있는지</strong>를 렉시컬 환경(lexical environment)이라고 부른다.</p><p>즉, 코드의 문맥은 렉시컬 환경으로 이뤄진다.<br> 이를 구현한 것이 <strong>실행 컨텍스트</strong>(execution context)이며, 모든 코드는 실행 컨텍스트에서 평가되고 실행된다.<br> 스코프는 실행 컨텍스트와 깊은 관련이 있다.</p><p>이에 대해서는 23장 &quot;실행 컨텍스트&quot;에서 자세히 살펴보자.</p></div><p>위 예제에서 코드의 가장 바깥 영역에 선언된 x 변수는 어디서든 참조할 수 있다.<br> 하지만 foo 함수 내부에서 선언된 x 변수는 foo 함수 내부에서만 참조할 수 있고 foo 함수 외부에서는 참조할 수 없다.<br> 이때 두 개의 x 변수는 식별자 이름이 동일하지만 스코프가 다른 별개의 변수다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/fcc775d7-ca4d-47d6-a12a-348b4c4453af" alt="그림 13-1. 스코프는 네임스페이스다." tabindex="0" loading="lazy"><figcaption>그림 13-1. 스코프는 네임스페이스다.</figcaption></figure><p>만약 스코프라는 개념이 없다면 같은 이름을 갖는 변수는 충돌을 일으키므로 프로그램 전체에서 하나밖에 사용할 수 없다.</p><p>예를 들어, 파일 이름은 하나의 파일을 구별하여 식별할 수 있는 식별자다.<br> 식별자인 파일 이름은 유일해야한다. 식별자인 파일 이름을 중복해서 사용할 수 있는 이유는 폴더라는 개념이 있기 때문이다.<br> 만약 폴더가 없다면 파일 이름은 유일해야 한다.</p><p>이와 마찬가지로 프로그래밍 언어에서는 스코프를 통해 식별자인 변수 이름의 충돌을 방지하여 같은 이름의 변수를 사용할 수 있게 한다.</p><div class="hint-container info"><p class="hint-container-title">var 키워드로 선언한 변수의 중복 선언</p><p><code>var</code> 키워드로 선언된 변수는 같은 스코프 내에서 중복 선언이 허용된다.</p><p>이는 의도치 않게 변수값이 재할당되어 변경되는 부작용을 발생시킨다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 2</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>하지만 <code>let</code>이나 <code>const</code> 키워드로 선언된 변수는 같은 스코프 내에서 중복 선언을 허용하지 않는다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
  <span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// SyntaxError: Identifier &#39;x&#39; has already been declared</span>
<span class="token punctuation">}</span>

<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></div><h2 id="_2-스코프의-종류" tabindex="-1"><a class="header-anchor" href="#_2-스코프의-종류" aria-hidden="true">#</a> 2. 스코프의 종류</h2><p>코드는 전역(global)과 지역(local)으로 구분할 수 있다.</p><table><thead><tr><th style="text-align:left;">구분</th><th style="text-align:left;">설명</th><th style="text-align:center;">스코프</th><th style="text-align:center;">변수</th></tr></thead><tbody><tr><td style="text-align:left;">전역</td><td style="text-align:left;">코드의 가장 바깥 영역</td><td style="text-align:center;">전역 스코프</td><td style="text-align:center;">전역 변수</td></tr><tr><td style="text-align:left;">지역</td><td style="text-align:left;">함수 몸체 내부</td><td style="text-align:center;">지역 스코프</td><td style="text-align:center;">지역 변수</td></tr></tbody></table><h3 id="_2-1-전역과-지역-스코프" tabindex="-1"><a class="header-anchor" href="#_2-1-전역과-지역-스코프" aria-hidden="true">#</a> 2.1 전역과 지역 스코프</h3><p>다음 예제를 살펴보자.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/21f35c27-627a-4eea-a568-59dcd1646a1a" alt="그림 13-2. 전역 스코프와 지역 스코프" tabindex="0" loading="lazy"><figcaption>그림 13-2. 전역 스코프와 지역 스코프</figcaption></figure><p>전역이란 코드의 가장 바깥 영역을 말한다. 전역에 변수를 선언하면 전역 스코프를 갖는 전역 변수가 된다.<br><strong>전역 변수는 어디서든지 참조할 수 있다.</strong> 전역 변수는 어디서든 참조할 수 있으므로 함수 내부에서도 참조할 수 있다.</p><h3 id="_2-2-지역과-지역스코프" tabindex="-1"><a class="header-anchor" href="#_2-2-지역과-지역스코프" aria-hidden="true">#</a> 2.2. 지역과 지역스코프</h3><p>지역이란 <strong>함수 몸체 내부</strong>를 말한다. 지역에 변수를 선언하면 지역 스코프를 갖는 지역 변수가 된다.<br><strong>지역 변수는 자신의 지역 스코프와 하위 지역 스코프에서 유효하다.</strong></p><h2 id="_3-스코프-체인" tabindex="-1"><a class="header-anchor" href="#_3-스코프-체인" aria-hidden="true">#</a> 3. 스코프 체인</h2><p>함수는 전역에서 정의할 수도 있고 함수 몸체 내부에서 정의할 수도 있다.<br> 함수 몸체 내부에서 함수가 정의된 것을 &#39;함수의 중첩&#39;이라 한다.</p><p>그리고 함수 몸체 내부에서 정의한 함수를 &#39;중첩 함수(nested function)&#39;,<br> 중첩 함수를 포함하는 함수를 &#39;외부 함수(outer function)&#39;이라 한다.</p><p>함수는 중첩이 될 수 있으므로 함수의 지역 스코프도 중첩될 수 있다.<br> 이는 <strong>스코프가 함수의 중첩에 의해 계층적 구조를 갖는다</strong>는 것을 의미한다.</p><p>앞의 예제(그림 13-2)에서 지역은 outer 함수의 지역과 inner 함수의 지역이 있다.<br> 이러한 계층 구조를 그림으로 나타내면 다음과 같다.</p><p>이렇게 스코프가 계층적으로 연결된 것을 <strong>스코프 체인</strong>(scope chain)이라 한다.</p><p><strong>변수를 참조할 때 자바스크립트 엔진은 스코프 체인을 통해 변수를 참조하는 코드의 스코프에서 시작하여 상위 스코프 방향으로 이동하며 선언된 변수를 검색(identifier resolution)한다.</strong></p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/a223a352-c648-403a-8fbe-c0a793a22055" alt="그림 13-3. 스코프 체인" tabindex="0" loading="lazy"><figcaption>그림 13-3. 스코프 체인</figcaption></figure><p>스코프 체인은 물리적인 실체로 존재한다.<br> 코드를 실행하기 앞서 위 그림과 유사한 자료구조인 렉시컬 환경(Lexical Environment)을 실제로 생성한다.<br> 변수 선언이 실행되면 변수 식별자가 이 자료구조(렉시컬 환경)에 키로 등록되고,<br> 변수 할당이 일어나면 이 자료구조의 변수 식별자에 해당하는 값을 변경한다.</p><div class="hint-container info"><p class="hint-container-title">렉시컬 환경(Lexical Environment)</p><p>스코프 체인은 실행 컨텍스트의 렉시컬 환경을 단방향으로 연결한 것이다.<br> 전역 렉시컬 환경은 코드가 로드되면 곧바로 생성되고 함수의 렉시컬 환경은 함수가 호출되면 곧바로 생성된다.</p><p>이에 대해서는 23장 &quot;실행 컨텍스트&quot;에서 자세히 살펴보자.</p></div><h3 id="_3-1-스코프-체인에-의한-변수-검색" tabindex="-1"><a class="header-anchor" href="#_3-1-스코프-체인에-의한-변수-검색" aria-hidden="true">#</a> 3.1. 스코프 체인에 의한 변수 검색</h3><p>위 예제(그림 13-2)의 ④,⑤,⑥을 살펴보자.</p><ul><li><p>④ x 변수를 참조하는 코드의 스코프인 inner 함수의 지역 스코프에서 x 변수가 선언되었는지 검색한다.<br> inner함수 내에는 선언된 x 변수가 존재한다. 따라서 검색된 변수를 참조하고 검색을 종료한다.</p></li><li><p>⑤ y 변수를 참조하는 코드의 스코프인 inner 함수의 지역 스코프에서 y 변수가 선언되었는지 검색한다.<br> inner -&gt; outer -&gt; 전역 스코프로 검색한 뒤 전역 스코프에서 y 변수의 선언을 참조하고 검색을 종료한다.</p></li><li><p>⑥ z 변수를 참조하는 코드의 스코프인 inner 함수의 지역 스코프에서 z 변수가 선언되었는지 검색한다.<br> inner -&gt; outer 순으로 검색한 뒤 outer 함수의 지역 스코프에서 z 변수의 선언을 참조하고 검색을 종료한다.</p></li></ul><h3 id="_3-2-스코프-체인에-의한-함수-검색" tabindex="-1"><a class="header-anchor" href="#_3-2-스코프-체인에-의한-함수-검색" aria-hidden="true">#</a> 3.2. 스코프 체인에 의한 함수 검색</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;global function foo&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 중첩 함수</span>
  <span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;local function foo&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ①</span>
<span class="token punctuation">}</span>

<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>①에서 foo 함수를 호출하면 자바스크립트 엔진은 함수를 호출하기 위해 먼저 함수를 가리키는 식별자 foo를 검색한다.</p><p>이처럼 함수도 식별자에 할당되기 때문에 스코프를 갖는다.<br> 사실 함수는 식별자에 함수 객체가 할당된 것 외에는 일반 변수와 다를 바 없다.<br> 따라서 스코프를 &quot;변수를 검색할 때 사용하는 규칙&quot;이라고 표현하기 보다는 &quot;<strong>식별자를 검색하는 규칙</strong>&quot;이라고 표현하는 편이 좀 더 적합하다.</p><h2 id="_4-함수-레벨-스코프" tabindex="-1"><a class="header-anchor" href="#_4-함수-레벨-스코프" aria-hidden="true">#</a> 4. 함수 레벨 스코프</h2><p>지역은 함수 몸체 내부를 말하고 지역은 지역 스코프를 만든다고 했다.<br> 이는 <strong>코드 블록이 아닌 함수에 의해서만 지역 스코프가 생성된다</strong>는 의미다.</p><p>C나 자바 등을 비롯한 대부분의 프로그래밍 언어는 함수 몸체만이 아니라 모든 코드 블록이 지역 스코프를 만든다.<br> 이러한 특성을 <strong>블록 레벨 스코프</strong>(block level scope)라 한다.</p><p>하지만 <strong>var 키워드로 선언된 변수는 오로지 함수의 코드 블록(함수 몸체)만을 지역 스코프로 인정</strong>한다.<br> 이러한 특성을 <strong>함수 레벨 스코프</strong>(function level scope)라 한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>전역 변수 x가 전선되었고 if 문의 코드 블록 내에도 x 변수가 선언되었다.<br> 이때 if문의 코드 블록 내에서 선언된 x 변수는 전역변수다.<br> var 키워드로 선언된 변수는 함수 레벨 스코프만 인정하기 때문에 함수 밖에서 var 키워드로 선언된 변수는 코드 블록 내에서 선언되었다 할지라도 모두 전역 변수다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 0 1 2 3 4</span>
<span class="token punctuation">}</span>

<span class="token comment">// 의도치 한게 변수의 값이 변경되었다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 5</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>var 키워드로 선언된 변수는 블록 레벨 스코프를 인정하지 안힉 때문에 i 변수는 전역 변수가 된다.<br> 따라서 전역 변수 i는 중복 선언되고 그 결과 의도치 않은 전역 변수의 값이 재할당 된다.</p><h2 id="_5-렉시컬-스코프" tabindex="-1"><a class="header-anchor" href="#_5-렉시컬-스코프" aria-hidden="true">#</a> 5. 렉시컬 스코프</h2><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
  <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ?</span>
<span class="token function">bar</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ?</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제의 실행 결과는 bar 함수의 상위 스코프가 무엇인지에 따라 결정된다.</p><ol><li><strong>함수를 어디서 호출</strong>했는지에 따라 함수의 상위 스코프를 결정한다.</li><li><strong>함수를 어디서 정의</strong>했는지에 따라 함수의 상위 스코프를 결정한다.</li></ol><p>첫 번째 방식으로 함수의 상위 스코프를 결정한다면 bar 함수의 상위 스코프는 foo 함수의 지역 스코프와 전역 스코프일 것이다. 두 번째 방식으로 함수의 상위 스코프를 결정한다면 bar 함수의 상위 스코프는 전역 스코프일 것이다.</p><p>첫 번째 방식을 동적 스코프(dynamic scope)라 한다.<br> 함수를 정의하는 시점에는 함수가 어디서 호출될지 알 수 없다.<br> 따라서 함수가 호출되는 시점에서 동적으로 상위 스코프를 결정해야하기 때문에 동적 스코프라고 부른다.</p><p>두 번째 방식을 렉시컬 스코프 또는 정적 스코프라 한다.<br> 동적 스코프 방식처럼 상위 스코프가 동적으로 변하지 않고 함수 정의가 평가되는 시점에 상위 스코프가 정적으로 결정되기 때문에 정적 스코프라고 부른다.</p><p>자바스크립트를 비롯한 대부분의 프로그래밍 언어는 렉시컬 스코프를 따른다.</p><p>bar함수가 호출되면 호출된 곳이 어디인지 관계없이 언제나 자신이 기억하고 있는 전역 스코프를 상위 스코프로 사용한다.<br> 따라서 위 예제를 실행하면 전역 변수 x의 값 1을 두 번 출력한다.</p><p>렉시컬 스코프는 클로저와 깊은 관계가 있다. 이에 대해서는 24장 &quot;클로저&quot;에서 자세히 살펴보자.</p>`,61),o=[e];function c(i,l){return s(),a("div",null,o)}const d=n(p,[["render",c],["__file","deepdive13.html.vue"]]);export{d as default};
